/**
 * SmartBAS BMS — Node-RED settings.js
 * ----------------------------------------------------------------------------
 * This file is generated by the SmartBAS installer at install time.
 * Tokens replaced during install:
 *   PORT_PLACEHOLDER              -> TCP port chosen on the installer page
 *   CREDENTIAL_SECRET_PLACEHOLDER -> per-install secret derived from MachineGuid
 *   INSTALL_PATH_PLACEHOLDER      -> install root (typically C:\SmartBAS)
 *
 * Site engineers may edit this file post-install. After editing, restart the
 * SmartBAS Windows service from services.msc to apply changes.
 * ----------------------------------------------------------------------------
 */

module.exports = {

    // ------------------------------------------------------------------------
    // User data directory — holds flows.json, credentials, context store.
    // Survives uninstall. Do not change unless you know what you are doing.
    // ------------------------------------------------------------------------
    userDir: 'INSTALL_PATH_PLACEHOLDER\\data',

    // ------------------------------------------------------------------------
    // Flow file inside userDir
    // ------------------------------------------------------------------------
    flowFile: 'flows.json',
    flowFilePretty: true,

    // ------------------------------------------------------------------------
    // Credentials secret — encrypts credentials.json. Generated per install
    // from the machine's MachineGuid. DO NOT change after first deploy, or
    // stored credentials will become unreadable.
    // ------------------------------------------------------------------------
    credentialSecret: "CREDENTIAL_SECRET_PLACEHOLDER",

    // ------------------------------------------------------------------------
    // HTTP server
    // ------------------------------------------------------------------------
    uiPort: PORT_PLACEHOLDER,
    uiHost: "0.0.0.0",

    // ------------------------------------------------------------------------
    // URL roots
    // ------------------------------------------------------------------------
    httpAdminRoot: '/',       // editor served from root
    httpNodeRoot:  '/api',    // user HTTP nodes served from /api
    // ui: { path: "ui" },    // dashboard path (default /ui)

    // ------------------------------------------------------------------------
    // API payload limit (raised for typical BMS payloads)
    // ------------------------------------------------------------------------
    apiMaxLength: '100mb',

    // ------------------------------------------------------------------------
    // Admin authentication — DISABLED by default.
    // To enable, generate a password hash via:
    //   node-red admin hash-pw
    // then uncomment the block below and restart the service.
    // ------------------------------------------------------------------------
    // adminAuth: {
    //     type: "credentials",
    //     users: [{
    //         username: "admin",
    //         password: "$2a$08$xxxxxxxxxxxxxxxxxxxxxxxxx",
    //         permissions: "*"
    //     }]
    // },

    // ------------------------------------------------------------------------
    // Logging — rotating file transport into C:\SmartBAS\logs\
    // ------------------------------------------------------------------------
    logging: {
        console: {
            level: "info",
            metrics: false,
            audit: false
        },
        file: {
            level: "info",
            metrics: false,
            audit: false,
            handler: function(conf) {
                const fs = require("fs");
                const path = require("path");
                const logDir = 'INSTALL_PATH_PLACEHOLDER\\logs';
                try { fs.mkdirSync(logDir, { recursive: true }); } catch (e) {}
                const logPath = path.join(logDir, "nodered.log");
                return function(msg) {
                    const line = "[" + new Date().toISOString() + "] [" +
                                 (msg.level >= 40 ? "INFO" :
                                  msg.level >= 30 ? "WARN" :
                                  msg.level >= 20 ? "ERROR" : "TRACE") + "] " +
                                 (msg.type ? "[" + msg.type + "] " : "") +
                                 (typeof msg.msg === "string" ? msg.msg : JSON.stringify(msg.msg)) +
                                 "\n";
                    try { fs.appendFileSync(logPath, line); } catch (e) {}
                };
            }
        }
    },

    // ------------------------------------------------------------------------
    // Context storage — in-memory + file-backed
    // ------------------------------------------------------------------------
    contextStorage: {
        default: { module: "memory" },
        file:    { module: "localfilesystem" }
    },

    // ------------------------------------------------------------------------
    // Security / runtime
    // ------------------------------------------------------------------------
    exportGlobalContextKeys: false,
    functionGlobalContext: {},
    functionExternalModules: true,

    // ------------------------------------------------------------------------
    // Editor theme — SmartBAS branding
    // ------------------------------------------------------------------------
    editorTheme: {
        header: {
            title: 'SmartBAS BMS System',
            image: 'INSTALL_PATH_PLACEHOLDER\\app\\packages\\node_modules\\@node-red\\editor-client\\public\\smartbas\\header.png',
            url: '/'
        },
        page: {
            title: 'SmartBAS BMS System',
            favicon: 'INSTALL_PATH_PLACEHOLDER\\app\\packages\\node_modules\\@node-red\\editor-client\\public\\smartbas\\favicon.ico'
        },
        login: {
            image: 'INSTALL_PATH_PLACEHOLDER\\app\\packages\\node_modules\\@node-red\\editor-client\\public\\smartbas\\logo.png'
        },
        palette: {
            editable: true
        },
        projects: {
            enabled: false
        },
        tours: false,
        menu: {
            'menu-item-help': {
                label: 'SmartBAS BMS Help',
                url: 'https://smartbas.local/docs'
            }
        }
    }
};
